const item = $input.first().json;
const body = item.body ?? item;
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!body || typeof body !== 'object') throw new Error('Invalid body');
if (typeof body.session_id !== 'string' || !uuidRe.test(body.session_id)) throw new Error('Invalid session_id');
if (typeof body.message !== 'string' || body.message.length === 0 || body.message.length > 1000) throw new Error('Invalid message');
return [{ json: {
  session_id: body.session_id,
  message: body.message,
  user_metadata: body.user_metadata ?? null,
  received_at: new Date().toISOString(),
} }];

const agentData = $json;
let reply = (agentData.output || agentData.text || '').toString();
// Sanitize: remove zero-width chars (modelo free a veces los emite)
reply = reply.replace(/[\u200B-\u200D\uFEFF\u2060]/g, '');
// Colapsar solo espacios/tabs consecutivos (no newlines — preserva saltos de linea para render markdown)
reply = reply.replace(/[ \t]{2,}/g, ' ');
// Remover triple-backticks que a veces emite grok envolviendo la respuesta
reply = reply.replace(/^```[a-z]*\s*\n?/i, '').replace(/\n?```\s*$/i, '');
// Limitar newlines consecutivos a max 2 (un parrafo en blanco)
reply = reply.replace(/\n{3,}/g, '\n\n');
reply = reply.trim();
if (reply.length < 3) {
  reply = 'Te comparto la informacion solicitada.';
}
const attachments = [];
const steps = agentData.intermediateSteps || [];

function pushAttachment(p) {
  if (!p || typeof p !== 'object') return;
  if (p.type === 'image' && p.url) {
    attachments.push({ type: 'image', url: p.url, caption: p.caption });
  } else if (p.type === 'image_floating' && p.url) {
    attachments.push({ type: 'image_floating', url: p.url, caption: p.caption, title: p.title });
  } else if (p.type === 'gallery' && Array.isArray(p.images)) {
    attachments.push({ type: 'gallery', images: p.images });
  } else if (p.type === 'gallery_floating' && Array.isArray(p.images)) {
    attachments.push({ type: 'gallery_floating', images: p.images, caption: p.caption });
  } else if (p.type === 'masterplan_floating' && p.url) {
    attachments.push({ type: 'masterplan_floating', url: p.url, caption: p.caption, title: p.title });
  } else if (p.type === 'tour360_floating' && p.url) {
    attachments.push({ type: 'tour360_floating', url: p.url, caption: p.caption, title: p.title, poster: p.poster });
  } else if (p.type === 'whatsapp_link' && p.url) {
    attachments.push({ type: 'whatsapp_link', url: p.url, label: p.label || 'Hablar con equipo de ventas por WhatsApp' });
  }
}

for (const step of steps) {
  const obs = step.observation ?? step.toolOutput ?? step;
  let parsed = obs;
  if (typeof obs === 'string') {
    try { parsed = JSON.parse(obs); } catch { continue; }
  }
  if (Array.isArray(parsed)) {
    for (const item of parsed) {
      const unwrapped = item && item.json ? item.json : item;
      pushAttachment(unwrapped);
    }
  } else {
    const unwrapped = parsed && parsed.json ? parsed.json : parsed;
    pushAttachment(unwrapped);
  }
}
return [{ json: { reply, attachments } }];

// Lee el CSV del Google Sheet y produce un resumen compacto lote->estado
// para inyectarlo en el system prompt del AI Agent.

const leadCtx = $('Get Lead Context').first().json || {};
const sheetItem = $input.first().json || {};
const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();

function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (c === ',' && !inQuotes) {
      row.push(field); field = '';
    } else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else {
      field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const normalizeEstado = (raw) => {
  const e = (raw || '').toString().trim().toLowerCase();
  if (e.startsWith('disponi')) return 'disponible';
  if (e.startsWith('reserv')) return 'reservado';
  if (e.startsWith('vendi')) return 'vendido';
  return null;
};

let inventarioTexto = '';
if (csvText && csvText.length > 100) {
  const rows = parseCsv(csvText);
  const disponibles = [];
  const reservadas = [];
  const vendidas = [];
  for (const r of rows) {
    if (!r || r.length < 3) continue;
    const lote = (r[1] || '').toString().trim().toUpperCase();
    if (!/^(\d{1,3}|B\d{1,2})$/.test(lote)) continue;
    const estado = normalizeEstado(r[2]);
    if (estado === 'disponible') disponibles.push(lote);
    else if (estado === 'reservado') reservadas.push(lote);
    else if (estado === 'vendido') vendidas.push(lote);
  }
  const sortLots = (arr) => arr.sort((a, b) => a.localeCompare(b, 'es', { numeric: true }));
  sortLots(disponibles); sortLots(reservadas); sortLots(vendidas);

  inventarioTexto = [
    `DISPONIBLES (${disponibles.length}): ${disponibles.join(', ') || '—'}`,
    `RESERVADAS (${reservadas.length}): ${reservadas.join(', ') || '—'}`,
    `VENDIDAS (${vendidas.length}): ${vendidas.join(', ') || '—'}`,
  ].join('\n');
} else {
  inventarioTexto = 'INVENTARIO NO DISPONIBLE EN ESTE TURNO — consulta la tool normalmente.';
}

return [{ json: {
  ...leadCtx,
  inventario_estados_texto: inventarioTexto,
} }];

// Captura los datos del turno para el tracking de costos.
// Se ejecuta DESPUÉS de Respond to Webhook — el usuario ya recibió la respuesta.
const validate = $('Validate Payload').first().json;
const agent = $('AI Agent').first().json;

const startedAt = validate.received_at || new Date().toISOString();
const endedAt = new Date().toISOString();
const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();

return [{
  json: {
    session_id: validate.session_id,
    workflow: 'main',
    workflow_id: 'II3VLrcHrtsKXMxQ',
    execution_id: $execution.id,
    model: 'x-ai/grok-4.1-fast',
    user_message: (validate.message || '').slice(0, 2000),
    agent_output: (agent.output || '').slice(0, 5000),
    started_at: startedAt,
    ended_at: endedAt,
    duration_ms: durationMs,
  }
}];
